struct ProductSalesReport {
  static constexpr const char* tablename = "ProductSalesReport";
  static constexpr bool is_view = true;
  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) return {};
  auto conn = conn_res.value();

  create_table<Product>(conn);
  create_table<Sale>(conn);

  std::string view_sql = R"(
    CREATE VIEW IF NOT EXISTS ProductSalesReport AS
    SELECT p.category AS category,
           SUM(s.quantity) AS total_qty,
           SUM(s.amount) AS total_amt
    FROM Product p
    INNER JOIN Sale s ON p.product_id = s.product_id
    GROUP BY p.category
    HAVING SUM(s.amount) > 5000.0;
  )";
  exec(conn, view_sql);

  auto rows = sqlgen::read<std::vector<ProductSalesReport>>(conn).value();
  std::vector<CategoryReport> out;
  out.reserve(rows.size());
  for (const auto& r : rows) {
    out.push_back({r.category, r.total_qty, r.total_amt});
  }
  return out;
}

}  // namespace query_product_sales_report

