        if (result2) {
            total_rows_affected += conn->changes();
        } else {
            return -1; // Second update failed
        }

    } catch (const std::exception& e) {
        return -1; // Error occurred during execution
    }

    return total_rows_affected;
}

} // namespace update_order_status
