 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // 2. Create the Account table using write with empty container
  std::vector<Account> empty_accounts;
  auto write_result = sqlgen::write(conn, empty_accounts);
  if (!write_result) {
    return false;
  }

  // 3. Update balances and statuses using set operations
  // Update account_id=1 to set balance to 100.0
  auto update_balance = sqlgen::update<Account>(sqlgen::col<"balance">.set(100.0)) 
                      | sqlgen::where(sqlgen::col<"account_id"> == 1);

  // Update account_id=2 to set status to "active"
  auto update_status = sqlgen::update<Account>(sqlgen::col<"status">.set("active")) 
                    | sqlgen::where(sqlgen::col<"account_id"> == 2);

  // Execute the update operations
  auto update_balance_result = update_balance(conn);
  if (!update_balance_result) {
    return false;
  }

  auto update_status_result = update_status(conn);
  if (!update_status_result) {
    return false;
  }

  // 4. Verify the updates by reading the data back
  auto read_result = sqlgen::read<std::vector<Account>>(conn);
  if (!read_result) {
    return false;
  }

  auto accounts = *read_result;

  // Check if the updates were successful
  bool success = true;

  // Verify account_id=1 has balance 100.0
  auto account1 = std::find_if(accounts.begin(), accounts.end(),
                               [](const Account& acc) { return acc.account_id == 1; });
  if (account1 != accounts.end() && account1->balance != 100.0) {
    success = false;
  }

  // Verify account_id=2 has status "active"
  auto account2 = std::find_if(accounts.begin(), accounts.end(),
                               [](const Account& acc) { return acc.account_id == 2; });
  if (account2 != accounts.end() && account2->status != "active") {
    success = false;
  }

  return success;
}

}  // namespace update_set_operations

