  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect();

  // Create tables
  conn | sqlgen::create_table<Department>;
  conn | sqlgen::create_table<Employee>;

  // Insert data
  conn | sqlgen::insert_into(depts);
  conn | sqlgen::insert_into(emps);

  // Define column references
  auto dept_name = "department_name"_t1;
  auto emp_first_name = "first_name"_t2;
  auto emp_last_name = "last_name"_t2;
  auto emp_salary = "salary"_t2;
  auto dept_id_t1 = "department_id"_t1;
  auto dept_id_t2 = "department_id"_t2;

  // INNER JOIN: Employees with assigned departments
  auto inner_query = select_from<Department, "d">(dept_name)
      | inner_join<Employee, "e">(dept_id_t1 == dept_id_t2)
      | select(emp_first_name, emp_last_name, emp_salary);

  // LEFT JOIN: All employees (including those without departments)
  auto left_query = select_from<Employee, "e">(emp_first_name, emp_last_name, emp_salary)
      | left_join<Department, "d">(dept_id_t2 == dept_id_t1);

  // RIGHT JOIN: All departments (including those without employees)
  auto right_query = select_from<Employee, "e">(emp_first_name, emp_last_name, emp_salary)
      | right_join<Department, "d">(dept_id_t2 == dept_id_t1);

  // FULL JOIN: All employees and departments
  auto full_query = select_from<Employee, "e">(emp_first_name, emp_last_name, emp_salary)
      | full_join<Department, "d">(dept_id_t2 == dept_id_t1);

  // Execute queries and collect results
  auto inner_results = sqlgen::read<std::vector<JoinResult>>(inner_query)(conn).value();
  auto left_results = sqlgen::read<std::vector<JoinResult>>(left_query)(conn).value();
  auto right_results = sqlgen::read<std::vector<JoinResult>>(right_query)(conn).value();
  auto full_results = sqlgen::read<std::vector<JoinResult>>(full_query)(conn).value();

  return JoinAnalysis{
      .inner_join_results = inner_results,
      .left_join_results = left_results,
      .right_join_results = right_results,
      .full_join_results = full_results
  };
}
}  // namespace analyze_department_employees
```

